1	use actix_web::dev::ServiceRequest;
2	use actix_web::{web, FromRequest, HttpRequest};
3	use std::future::Future;
4	use std::pin::Pin;
5	use uuid::Uuid;
6	
7	use crate::db::DbPool;
8	use crate::errors::AppError;
9	use crate::models::session::Session;
10	use crate::models::user::User;
11	
12	/// Stored in request extensions after token validation.
13	#[derive(Debug, Clone)]
14	pub struct AuthenticatedUser {
15	    pub user_id: Uuid,
16	    pub username: String,
17	    pub roles: Vec<String>,
18	    pub account_state: String,
19	}
20	
21	/// Extract Bearer token from the Authorization header.
22	pub fn extract_bearer_token(req: &ServiceRequest) -> Option<String> {
23	    req.headers()
24	        .get("Authorization")
25	        .and_then(|v| v.to_str().ok())
26	        .and_then(|v| v.strip_prefix("Bearer "))
27	        .map(|s| s.to_string())
28	}
29	
30	/// Validate the token against the sessions table and build an AuthenticatedUser.
31	pub async fn resolve_authenticated_user(
32	    pool: &DbPool,
33	    token: &str,
34	) -> Result<AuthenticatedUser, AppError> {
35	    // 1. Look up a non-expired session by token.
36	    let session = sqlx::query_as::<_, Session>(
37	        "SELECT id, user_id, token, created_at, expires_at, ip_address, user_agent \
38	         FROM sessions \
39	         WHERE token = $1 AND expires_at > NOW()",
40	    )
41	    .bind(token)
42	    .fetch_optional(pool)
43	    .await?;
44	
45	    let session = session.ok_or_else(|| {
46	        AppError::Unauthorized("Invalid or expired session".into())
47	    })?;
48	
49	    // 2. Load the associated user.
50	    let user = sqlx::query_as::<_, User>(
51	        "SELECT id, username, email, password_hash, display_name, account_state, \
52	         created_at, updated_at \
53	         FROM users \
54	         WHERE id = $1",
55	    )
56	    .bind(session.user_id)
57	    .fetch_optional(pool)
58	    .await?;
59	
60	    let user = user.ok_or_else(|| {
61	        AppError::Unauthorized("User associated with session no longer exists".into())
62	    })?;
63	
64	    // 3. Verify account is active.
65	    if user.account_state != "active" {
66	        return Err(AppError::Forbidden(format!(
67	            "Account is {}",
68	            user.account_state
69	        )));
70	    }
71	
72	    // 4. Fetch roles.
73	    let role_rows = sqlx::query_scalar::<_, String>(
74	        "SELECT r.name FROM roles r \
75	         JOIN user_roles ur ON r.id = ur.role_id \
76	         WHERE ur.user_id = $1",
77	    )
78	    .bind(user.id)
79	    .fetch_all(pool)
80	    .await?;
81	
82	    Ok(AuthenticatedUser {
83	        user_id: user.id,
84	        username: user.username,
85	        roles: role_rows,
86	        account_state: user.account_state,
87	    })
88	}
89	
90	/// Request-scoped authenticated user. Use as a handler parameter to require authentication.
91	/// Returns 401 if no/invalid token, 403 if account blocked.
92	pub struct AuthContext(pub AuthenticatedUser);
93	
94	impl AuthContext {
95	    pub fn user(&self) -> &AuthenticatedUser {
96	        &self.0
97	    }
98	
99	    /// Returns Forbidden if the user does not have the specified role.
100	    pub fn require_role(&self, role: &str) -> Result<(), AppError> {
101	        if self.0.roles.iter().any(|r| r == role) {
102	            Ok(())
103	        } else {
104	            Err(AppError::Forbidden(format!(
105	                "This action requires the {} role.",
106	                role
107	            )))
108	        }
109	    }
110	
111	    /// Returns Forbidden if the user has none of the specified roles.
112	    pub fn require_any_role(&self, roles: &[&str]) -> Result<(), AppError> {
113	        if roles.iter().any(|r| self.0.roles.iter().any(|ur| ur == r)) {
114	            Ok(())
115	        } else {
116	            Err(AppError::Forbidden(
117	                "You do not have permission to perform this action.".into(),
118	            ))
119	        }
120	    }
121	
122	    pub fn is_admin(&self) -> bool {
123	        self.0.roles.iter().any(|r| r == "Administrator")
124	    }
125	
126	    pub fn is_teacher(&self) -> bool {
127	        self.0.roles.iter().any(|r| r == "Teacher")
128	    }
129	}
130	
131	impl FromRequest for AuthContext {
132	    type Error = AppError;
133	    type Future = Pin<Box<dyn Future<Output = Result<Self, Self::Error>>>>;
134	
135	    fn from_request(req: &HttpRequest, _payload: &mut actix_web::dev::Payload) -> Self::Future {
136	        let token = req
137	            .headers()
138	            .get("Authorization")
139	            .and_then(|v| v.to_str().ok())
140	            .and_then(|v| v.strip_prefix("Bearer "))
141	            .map(|s| s.to_string());
142	
143	        let pool = req.app_data::<web::Data<crate::db::DbPool>>().cloned();
144	
145	        Box::pin(async move {
146	            let token = token.ok_or_else(|| {
147	                AppError::Unauthorized("Missing Authorization header".into())
148	            })?;
149	            let pool = pool.ok_or_else(|| {
150	                AppError::InternalError("DB pool not configured".into())
151	            })?;
152	            let user = resolve_authenticated_user(pool.get_ref(), &token).await?;
153	            Ok(AuthContext(user))
154	        })
155	    }
156	}
157	
158	/// Verify that a user (teacher or admin) has access to the given class.
159	/// Admins pass unconditionally. Teachers must be assigned to the class.
160	/// Other roles are rejected.
161	pub async fn require_class_access(
162	    auth: &AuthContext,
163	    pool: &crate::db::DbPool,
164	    class_id: Uuid,
165	) -> Result<(), AppError> {
166	    if auth.is_admin() {
167	        return Ok(());
168	    }
169	    if !auth.is_teacher() {
170	        return Err(AppError::Forbidden(
171	            "Only teachers and administrators can access class data.".into(),
172	        ));
173	    }
174	    let count: i64 = sqlx::query_scalar(
175	        "SELECT COUNT(*) FROM classes WHERE id = $1 AND teacher_id = $2",
176	    )
177	    .bind(class_id)
178	    .bind(auth.0.user_id)
179	    .fetch_one(pool)
180	    .await?;
181	
182	    if count == 0 {
183	        return Err(AppError::Forbidden(
184	            "You are not assigned to this class.".into(),
185	        ));
186	    }
187	    Ok(())
188	}
189	
190	/// Verify that a user has access to the given school.
191	/// Admins pass. Teachers/AcademicStaff must be in user_school_assignments.
192	pub async fn require_school_access(
193	    auth: &AuthContext,
194	    pool: &crate::db::DbPool,
195	    school_id: Uuid,
196	) -> Result<(), AppError> {
197	    if auth.is_admin() {
198	        return Ok(());
199	    }
200	    let count: i64 = sqlx::query_scalar(
201	        "SELECT COUNT(*) FROM user_school_assignments WHERE school_id = $1 AND user_id = $2",
202	    )
203	    .bind(school_id)
204	    .bind(auth.0.user_id)
205	    .fetch_one(pool)
206	    .await?;
207	
208	    if count == 0 {
209	        return Err(AppError::Forbidden(
210	            "You are not assigned to this school.".into(),
211	        ));
212	    }
213	    Ok(())
214	}
