1	use actix_web::{HttpResponse, ResponseError};
2	use serde_json::json;
3	use thiserror::Error;
4	
5	#[derive(Debug, Error)]
6	pub enum AppError {
7	    #[error("Database error: {0}")]
8	    DatabaseError(#[from] sqlx::Error),
9	
10	    #[error("Not found: {0}")]
11	    NotFound(String),
12	
13	    #[error("Unauthorized: {0}")]
14	    Unauthorized(String),
15	
16	    #[error("Forbidden: {0}")]
17	    Forbidden(String),
18	
19	    #[error("Validation error: {0}")]
20	    ValidationError(String),
21	
22	    #[error("Internal error: {0}")]
23	    InternalError(String),
24	
25	    #[error("Conflict: {0}")]
26	    ConflictError(String),
27	
28	    #[error("Too many requests: {0}")]
29	    TooManyRequests(String),
30	}
31	
32	impl AppError {
33	    /// Returns a message safe to send to the client (no internal details)
34	    pub fn client_message(&self) -> &str {
35	        match self {
36	            AppError::Unauthorized(_) => "Invalid username or password.",
37	            AppError::TooManyRequests(_) => {
38	                "Too many failed login attempts. Please wait before trying again."
39	            }
40	            AppError::Forbidden(msg) => msg.as_str(),
41	            AppError::NotFound(_) => "Resource not found.",
42	            AppError::ValidationError(msg) => msg.as_str(),
43	            AppError::ConflictError(msg) => msg.as_str(),
44	            AppError::DatabaseError(_) | AppError::InternalError(_) => {
45	                "An internal error occurred."
46	            }
47	        }
48	    }
49	}
50	
51	impl ResponseError for AppError {
52	    fn error_response(&self) -> HttpResponse {
53	        let body = json!({ "error": self.client_message() });
54	
55	        match self {
56	            AppError::DatabaseError(_) => HttpResponse::InternalServerError().json(body),
57	            AppError::NotFound(_) => HttpResponse::NotFound().json(body),
58	            AppError::Unauthorized(_) => HttpResponse::Unauthorized().json(body),
59	            AppError::Forbidden(_) => HttpResponse::Forbidden().json(body),
60	            AppError::ValidationError(_) => HttpResponse::UnprocessableEntity().json(body),
61	            AppError::InternalError(_) => HttpResponse::InternalServerError().json(body),
62	            AppError::ConflictError(_) => HttpResponse::Conflict().json(body),
63	            AppError::TooManyRequests(_) => HttpResponse::TooManyRequests().json(body),
64	        }
65	    }
66	}
67	
68	impl From<argon2::password_hash::Error> for AppError {
69	    fn from(e: argon2::password_hash::Error) -> Self {
70	        match e {
71	            argon2::password_hash::Error::Password => {
72	                AppError::Unauthorized("Invalid credentials".into())
73	            }
74	            other => AppError::InternalError(other.to_string()),
75	        }
76	    }
77	}
