    notes: Option<String>,
}

#[derive(Serialize, sqlx::FromRow)]
struct DashboardLowStockRow {
    product_id: Uuid,
    product_name: String,
    quantity: i32,
    low_stock_threshold: i32,
}

#[derive(Serialize)]
struct OrdersDashboardResponse {
    pending_orders: i64,
    confirmed_orders: i64,
    fulfilled_orders: i64,
    cancelled_orders: i64,
    pending_over_30_min: i64,
