            let fulfilled: i64 = sqlx::query_scalar(
                "SELECT COUNT(*) FROM orders
                 WHERE status = 'fulfilled'
                   AND user_id IN (
                       SELECT usa.user_id FROM user_school_assignments usa
                       JOIN schools s ON s.id = usa.school_id
