    async fn test_filter_decision_pending_excludes_approved() {
        let pool = test_pool().await;
        let suffix = Uuid::new_v4().to_string()[..8].to_string();

        let admin_id = seed_user(&pool, &format!("fp_admin_{}", suffix), "Administrator").await;
