use std::env;
use uuid::Uuid;
use chrono::Utc;
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;

// ---------------------------------------------------------------------------
// Helper: connect and migrate
// ---------------------------------------------------------------------------

async fn test_pool() -> PgPool {
