12	use std::env;
13	use uuid::Uuid;
14	
15	// ---------------------------------------------------------------------------
16	// Helper: get test pool or skip
17	// ---------------------------------------------------------------------------
18	
19	async fn test_pool() -> Option<sqlx::PgPool> {
20	    let url = env::var("TEST_DATABASE_URL").ok()?;
21	    sqlx::PgPool::connect(&url).await.ok()
22	}
