24	// ============================================================================
25	// Scope resolution logic tests (pure — no DB)
26	// ============================================================================
27	
28	mod scope_resolution {
29	
30	    /// An admin with no scope rows is a super-admin: `None` means unrestricted.
31	    #[test]
32	    fn no_scope_rows_means_super_admin() {
33	        // Mirrors get_admin_campus_scope() returning None when the assignments
34	        // table has no rows for this admin.
35	        let scope: Option<Vec<uuid::Uuid>> = None;
36	        assert!(scope.is_none(), "super-admin scope must be None");
37	    }
38	
39	    /// An admin with scope rows must have Some(ids), even if the list is empty
40	    /// after expansion (e.g., a district with no campuses yet).
41	    #[test]
42	    fn scope_rows_present_yields_some() {
43	        let campus_ids: Vec<uuid::Uuid> = vec![uuid::Uuid::new_v4()];
44	        let scope = Some(campus_ids);
45	        assert!(scope.is_some());
46	    }
47	
48	    /// District expansion: each district row should contribute the campus IDs
49	    /// belonging to that district.
50	    #[test]
51	    fn district_scope_expands_to_campus_ids() {
52	        let c1 = uuid::Uuid::new_v4();
53	        let c2 = uuid::Uuid::new_v4();
54	        // Simulates two campuses returned for one district scope row.
