86	// ============================================================================
87	// 403 guard logic tests (pure — no DB)
88	// ============================================================================
89	
90	mod scope_enforcement {
91	
92	    fn check_user_in_scope(
93	        scope: &Option<Vec<uuid::Uuid>>,
94	        user_campus_ids: &[uuid::Uuid],
95	    ) -> Result<(), &'static str> {
96	        let allowed = match scope {
97	            None => return Ok(()), // super-admin: always allowed
98	            Some(ids) => ids,
99	        };
100	        let in_scope = user_campus_ids.iter().any(|c| allowed.contains(c));
101	        if in_scope {
102	            Ok(())
103	        } else {
104	            Err("Forbidden: Target user is outside your administrative scope.")
105	        }
106	    }
107	
108	    /// Super-admin (None scope) can always access any user.
109	    #[test]
110	    fn super_admin_always_passes_user_check() {
111	        let scope: Option<Vec<uuid::Uuid>> = None;
112	        let result = check_user_in_scope(&scope, &[uuid::Uuid::new_v4()]);
113	        assert!(result.is_ok());
114	    }
115	
116	    /// Super-admin passes even when the user has no campus assignment.
117	    #[test]
118	    fn super_admin_passes_for_user_with_no_campus() {
119	        let scope: Option<Vec<uuid::Uuid>> = None;
120	        let result = check_user_in_scope(&scope, &[]);
121	        assert!(result.is_ok());
122	    }
123	
124	    /// Scoped admin can access a user whose campus is in their allowed list.
125	    #[test]
126	    fn scoped_admin_allows_user_in_scope() {
127	        let allowed_campus = uuid::Uuid::new_v4();
128	        let scope = Some(vec![allowed_campus]);
129	        let result = check_user_in_scope(&scope, &[allowed_campus]);
130	        assert!(result.is_ok());
131	    }
132	
133	    /// Scoped admin is blocked from accessing a user in a different campus.
134	    #[test]
135	    fn scoped_admin_blocks_user_outside_scope() {
136	        let allowed_campus = uuid::Uuid::new_v4();
137	        let other_campus = uuid::Uuid::new_v4();
138	        let scope = Some(vec![allowed_campus]);
139	        let result = check_user_in_scope(&scope, &[other_campus]);
140	        assert!(result.is_err());
141	        assert!(result.unwrap_err().contains("Forbidden"));
142	    }
143	
144	    /// Scoped admin is blocked when the user has no campus assignment at all.
145	    #[test]
146	    fn scoped_admin_blocks_user_with_no_campus_assignment() {
147	        let scope = Some(vec![uuid::Uuid::new_v4()]);
148	        let result = check_user_in_scope(&scope, &[]);
149	        assert!(result.is_err());
150	    }
151	
152	    /// A user assigned to multiple campuses passes if any one matches.
153	    #[test]
154	    fn user_with_multiple_campuses_passes_if_one_matches() {
155	        let allowed = uuid::Uuid::new_v4();
156	        let other = uuid::Uuid::new_v4();
157	        let scope = Some(vec![allowed]);
158	        // user is in both campuses (e.g. transferred)
159	        let result = check_user_in_scope(&scope, &[other, allowed]);
160	        assert!(result.is_ok());
161	    }
162	
163	    /// A scoped admin with an empty campus list (e.g. district has no campuses)
164	    /// cannot access any user.
165	    #[test]
166	    fn scoped_admin_with_empty_campus_list_blocks_all() {
167	        let scope: Option<Vec<uuid::Uuid>> = Some(vec![]);
168	        let result = check_user_in_scope(&scope, &[uuid::Uuid::new_v4()]);
169	        assert!(result.is_err());
170	    }
171	
172	    /// Error message from scope check is meaningful (not empty).
173	    #[test]
174	    fn scope_error_message_is_meaningful() {
175	        let scope = Some(vec![uuid::Uuid::new_v4()]);
176	        let err = check_user_in_scope(&scope, &[]).unwrap_err();
177	        assert!(!err.is_empty());
178	        assert!(err.len() > 10);
179	    }
180	}
