262	/// Verify a scoped admin cannot see a user outside their campus via list_users query.
263	#[tokio::test]
264	#[ignore = "requires TEST_DATABASE_URL with seeded data"]
265	async fn test_scoped_admin_user_list_excludes_out_of_scope_users() {
