268	    // Find a campus that has at least one school with enrolled users.
269	    let campus_id: Option<Uuid> = sqlx::query_scalar(
270	        "SELECT s.campus_id FROM user_school_assignments usa
271	         JOIN schools s ON s.id = usa.school_id
272	         LIMIT 1",
