// ============================================================================
// HTTP-level runtime tests — validate assert_user_in_scope and
// assert_order_in_scope actually fire on the live request path.
//
// These tests seed their own isolated data using unique suffixes so they
// can run against the same database as the seeded-data tests without
// corrupting seeded rows.
// ============================================================================

/// Shared seed helpers for HTTP-level tests.
mod http_helpers {
    use sqlx::PgPool;
    use uuid::Uuid;

    pub async fn seed_user(pool: &PgPool, username: &str, role: &str) -> Uuid {
        let hash = meridian_backend::services::auth::hash_password("TestPass2024!!")
            .expect("hash failed");
        sqlx::query(
            "INSERT INTO users (id, username, email, password_hash, account_state,
                                is_super_admin, created_at, updated_at)
             VALUES (gen_random_uuid(), $1, $2, $3, 'active', false, NOW(), NOW())
             ON CONFLICT (username) DO UPDATE
               SET password_hash = EXCLUDED.password_hash,
                   account_state = 'active',
                   is_super_admin = false,
                   updated_at = NOW()",
        )
        .bind(username)
        .bind(format!("{}@test.local", username))
        .bind(&hash)
        .execute(pool)
        .await
        .expect("seed_user failed");

        let user_id: Uuid = sqlx::query_scalar("SELECT id FROM users WHERE username = $1")
            .bind(username)
            .fetch_one(pool)
            .await
            .expect("user not found");

        let role_id: i32 = sqlx::query_scalar("SELECT id FROM roles WHERE name = $1")
            .bind(role)
            .fetch_one(pool)
            .await
            .expect("role not found");

        sqlx::query(
            "INSERT INTO user_roles (user_id, role_id) VALUES ($1, $2) ON CONFLICT DO NOTHING",
        )
        .bind(user_id)
        .bind(role_id)
        .execute(pool)
        .await
        .expect("user_roles failed");

        user_id
    }

    pub async fn seed_super_admin(pool: &PgPool, username: &str) -> Uuid {
        let id = seed_user(pool, username, "Administrator").await;
        sqlx::query("UPDATE users SET is_super_admin = true WHERE id = $1")
            .bind(id)
            .execute(pool)
            .await
            .expect("set is_super_admin failed");
        id
    }

    pub async fn seed_campus(pool: &PgPool, suffix: &str) -> Uuid {
        let district_id = Uuid::new_v4();
        sqlx::query(
            "INSERT INTO districts (id, name, state, created_at) VALUES ($1, $2, 'TX', NOW())",
        )
        .bind(district_id)
        .bind(format!("District_{}", suffix))
        .execute(pool)
        .await
        .expect("seed district failed");

        let campus_id = Uuid::new_v4();
        sqlx::query(
            "INSERT INTO campuses (id, district_id, name, created_at) VALUES ($1, $2, $3, NOW())",
        )
        .bind(campus_id)
        .bind(district_id)
        .bind(format!("Campus_{}", suffix))
        .execute(pool)
        .await
        .expect("seed campus failed");

        campus_id
    }

    pub async fn seed_school(pool: &PgPool, campus_id: Uuid, suffix: &str) -> Uuid {
        let school_id = Uuid::new_v4();
        sqlx::query(
            "INSERT INTO schools (id, campus_id, name, school_type, created_at)
             VALUES ($1, $2, $3, 'general', NOW())",
        )
        .bind(school_id)
        .bind(campus_id)
        .bind(format!("School_{}", suffix))
        .execute(pool)
        .await
        .expect("seed school failed");
        school_id
    }

    pub async fn assign_user_to_school(pool: &PgPool, user_id: Uuid, school_id: Uuid) {
        sqlx::query(
            "INSERT INTO user_school_assignments (user_id, school_id, assignment_type, assigned_at)
             VALUES ($1, $2, 'student', NOW()) ON CONFLICT DO NOTHING",
        )
        .bind(user_id)
        .bind(school_id)
        .execute(pool)
        .await
        .expect("assign_user_to_school failed");
    }

    pub async fn assign_admin_to_campus(pool: &PgPool, admin_id: Uuid, campus_id: Uuid) {
        sqlx::query(
            "INSERT INTO admin_scope_assignments (admin_id, scope_type, scope_id)
             VALUES ($1, 'campus', $2) ON CONFLICT DO NOTHING",
        )
        .bind(admin_id)
        .bind(campus_id)
        .execute(pool)
        .await
        .expect("assign_admin_to_campus failed");
    }

    pub async fn seed_product(pool: &PgPool, suffix: &str) -> Uuid {
        let id = Uuid::new_v4();
        sqlx::query(
            "INSERT INTO products (id, name, price_cents, sku, category, active)
             VALUES ($1, $2, 100, $3, 'Test', true) ON CONFLICT (sku) DO NOTHING",
        )
        .bind(id)
        .bind(format!("Product_{}", suffix))
        .bind(format!("SKU-{}", suffix))
        .execute(pool)
        .await
        .expect("seed product failed");
        sqlx::query(
            "INSERT INTO inventory (product_id, quantity, low_stock_threshold)
             VALUES ($1, 50, 5) ON CONFLICT (product_id) DO UPDATE SET quantity = 50",
        )
        .bind(id)
        .execute(pool)
        .await
        .expect("seed inventory failed");
        id
    }

    pub async fn seed_order(pool: &PgPool, user_id: Uuid, product_id: Uuid) -> Uuid {
        let order_id = Uuid::new_v4();
        sqlx::query(
            "INSERT INTO orders (id, user_id, status, subtotal_cents, shipping_fee_cents,
                                 total_cents, points_earned, created_at, updated_at)
             VALUES ($1, $2, 'pending', 100, 695, 795, 1, NOW(), NOW())",
        )
        .bind(order_id)
        .bind(user_id)
        .execute(pool)
        .await
        .expect("seed order failed");
        sqlx::query(
            "INSERT INTO order_items (id, order_id, product_id, quantity, unit_price_cents,
                                      line_total_cents, created_at)
             VALUES (gen_random_uuid(), $1, $2, 1, 100, 100, NOW())",
        )
        .bind(order_id)
        .bind(product_id)
        .execute(pool)
        .await
        .expect("seed order_item failed");
        order_id
    }

    pub async fn login(
        app: &impl actix_web::dev::Service<
            actix_http::Request,
            Response = actix_web::dev::ServiceResponse,
            Error = actix_web::Error,
        >,
        username: &str,
    ) -> String {
        use actix_web::test::{call_service, read_body_json, TestRequest};
        let req = TestRequest::post()
            .uri("/api/v1/auth/login")
            .set_json(serde_json::json!({
                "username": username,
                "password": "TestPass2024!!"
            }))
            .to_request();
        let resp = call_service(app, req).await;
        let body: serde_json::Value = read_body_json(resp).await;
        body["token"]
            .as_str()
            .expect("login did not return token")
            .to_string()
    }
}

