/// Super-admin gets 200 for the same call.
#[actix_web::test]
#[ignore = "requires TEST_DATABASE_URL with applied migrations"]
async fn test_set_user_state_blocked_outside_scope() {
    let pool = migrating_pool().await;
    let suffix = Uuid::new_v4().to_string()[..8].to_string();

    // Two independent campuses.
    let campus_a = http_helpers::seed_campus(&pool, &format!("a_{}", suffix)).await;
    let campus_b = http_helpers::seed_campus(&pool, &format!("b_{}", suffix)).await;
    let school_a = http_helpers::seed_school(&pool, campus_a, &format!("a_{}", suffix)).await;
    let school_b = http_helpers::seed_school(&pool, campus_b, &format!("b_{}", suffix)).await;

    // scoped_adm is restricted to campus_a only.
    let scoped_adm = http_helpers::seed_user(
        &pool,
        &format!("scoped_adm_{}", suffix),
        "Administrator",
    )
    .await;
    http_helpers::assign_admin_to_campus(&pool, scoped_adm, campus_a).await;

    // super_adm is a super-admin with no restrictions.
    let super_adm = http_helpers::seed_super_admin(
        &pool,
        &format!("super_adm_{}", suffix),
    )
    .await;

    // target_a: user assigned to campus_a (in scope for scoped_adm).
    let target_a = http_helpers::seed_user(
        &pool,
        &format!("target_a_{}", suffix),
        "Student",
    )
    .await;
    http_helpers::assign_user_to_school(&pool, target_a, school_a).await;

    // target_b: user assigned to campus_b (out of scope for scoped_adm).
    let target_b = http_helpers::seed_user(
        &pool,
        &format!("target_b_{}", suffix),
        "Student",
    )
    .await;
    http_helpers::assign_user_to_school(&pool, target_b, school_b).await;

    let app = init_service(
        App::new()
            .app_data(web::Data::new(pool.clone()))
            .configure(meridian_backend::routes::configure_routes),
    )
    .await;

    let scoped_token = http_helpers::login(&app, &format!("scoped_adm_{}", suffix)).await;
    let super_token = http_helpers::login(&app, &format!("super_adm_{}", suffix)).await;

    // Scoped admin → in-scope user: must succeed (200).
    let resp = call_service(
        &app,
        TestRequest::post()
            .uri(&format!("/api/v1/admin/users/{}/set-state", target_a))
            .insert_header(("Authorization", format!("Bearer {}", scoped_token)))
            .set_json(json!({ "state": "active" }))
            .to_request(),
    )
    .await;
    assert_eq!(
        resp.status(), 200,
        "scoped admin must succeed on in-scope user"
    );

    // Scoped admin → out-of-scope user: must be blocked (403).
    let resp = call_service(
        &app,
        TestRequest::post()
            .uri(&format!("/api/v1/admin/users/{}/set-state", target_b))
            .insert_header(("Authorization", format!("Bearer {}", scoped_token)))
            .set_json(json!({ "state": "active" }))
            .to_request(),
    )
    .await;
    assert_eq!(
        resp.status(), 403,
        "scoped admin must be blocked for out-of-scope user"
    );

    // Super-admin → out-of-scope user: must succeed (no campus restriction).
    let resp = call_service(
        &app,
        TestRequest::post()
            .uri(&format!("/api/v1/admin/users/{}/set-state", target_b))
            .insert_header(("Authorization", format!("Bearer {}", super_token)))
            .set_json(json!({ "state": "active" }))
            .to_request(),
    )
    .await;
    assert_eq!(
        resp.status(), 200,
        "super-admin must succeed on any user"
    );
}

